import{_ as a,c as e,o as n,a4 as t}from"./chunks/framework.BYXEmrUe.js";const k=JSON.parse('{"title":"qiankun微前端","description":"","frontmatter":{},"headers":[],"relativePath":"project/web/qiankun.md","filePath":"project/web/qiankun.md","lastUpdated":null}'),r={name:"project/web/qiankun.md"},i=t('<h1 id="qiankun微前端" tabindex="-1">qiankun微前端 <a class="header-anchor" href="#qiankun微前端" aria-label="Permalink to &quot;qiankun微前端&quot;">​</a></h1><p>qiankun是一种微前端框架，可以将多个前端应用集成为一个整体。每个子应用可以使用不用的框架和技术栈，它们之前可以独立开发和部署，qiankun提供了一套完整的生命周期函数和通信机制 可以让不用的子应用之间进行跨框架和跨域的通信和交互<br> 具体查看官网: <a href="https://qiankun.umijs.org/zh/guide" target="_blank" rel="noreferrer">跳转地址</a></p><h2 id="微前端架构的核心价值" tabindex="-1">微前端架构的核心价值 <a class="header-anchor" href="#微前端架构的核心价值" aria-label="Permalink to &quot;微前端架构的核心价值&quot;">​</a></h2><ol><li>技术栈无关<br> 主框架不限制接入应用的技术栈，微应用具备完全自主权</li><li>独立开发、独立部署<br> 微应用仓库独立，前后端可独立开发，部署完成后主框架自动完成同步更新</li><li>增量升级<br> 在面对各种复杂场景时，我们通常很难对一个已经存在的系统做全量的技术栈升级或重构，而微前端是一种非常好的实施渐进式重构的手段和策略</li><li>独立运行时<br> 每个微应用之间状态隔离，运行时状态不共享</li></ol><p>微前端架构旨在解决单体应用在一个相对长的时间跨度下，由于参与的人员、团队的增多、变迁，从一个普通应用演变成一个巨石应用(Frontend Monolith)后，随之而来的应用不可维护的问题。这类问题在企业级 Web 应用中尤其常见。</p>',5),o=[i];function l(s,_,c,u,d,h){return n(),e("div",null,o)}const q=a(r,[["render",l]]);export{k as __pageData,q as default};
